 1	import type { FC } from 'react';
 2	import { DisplayTitle } from 'src/components/DetailItems/DetailItem';
 3	import { defaultOnConfirmWithIntValue } from 'src/modules/Providers/modals/EditModal/utils/defaultOnConfirm';
 4	import { useForkliftTranslation } from 'src/utils/i18n';
 5	
 6	import { ForkliftControllerModel, type K8sResourceCommon } from '@kubev2v/types';
 7	import { Text } from '@patternfly/react-core';
 8	import { MTV_SETTINGS } from '@utils/links';
 9	
10	import { EditField } from '../cards/EditField';
11	import type { InputComponentType } from '../cards/EditFieldTypes';
12	
13	import type { EditSettingsProps } from './EditSettingsProps';
14	import { preCopyIntervalOptions } from './options';
15	import SettingsSelectInput from './SettingsSelectInput';
16	
17	/**
18	 * PrecopyIntervalSelect component.
19	 * Wraps the SettingsSelectInput component with pre-defined options.
20	 */
21	const PrecopyIntervalSelect: InputComponentType = (props) => {
22	  return <SettingsSelectInput {...props} options={preCopyIntervalOptions} />;
23	};
24	
25	const EditPreCopyInterval: FC<EditSettingsProps> = (props) => {
26	  const { t } = useForkliftTranslation();
27	
28	  return (
29	    <EditField
30	      {...props}
31	      resource={props.resource as K8sResourceCommon}
32	      jsonPath={'spec.controller_precopy_interval'}
33	      label={
34	        <DisplayTitle
35	          title={t('Precopy interval')}
36	          showHelpIconNextToTitle
37	          moreInfoLink={MTV_SETTINGS}
38	          helpContent={
39	            <Text>
40	              {t(
41	                'Controls the interval at which a new snapshot is requested prior to initiating a warm migration. The default value is 60 minutes.',
42	              )}
43	            </Text>
44	          }
45	          crumbs={['spec', 'controller_precopy_interval']}
46	        />
47	      }
48	      model={ForkliftControllerModel}
49	      helperText={t(
50	        'Enter the interval in minutes for precopy. If empty, the default value will be used.',
51	      )}
52	      InputComponent={PrecopyIntervalSelect}
53	      onConfirmHook={defaultOnConfirmWithIntValue}
54	      defaultValue="60"
55	    />
56	  );
57	};
58	
59	export default EditPreCopyInterval;

